import axios from 'axios';

const api = axios.create({
  baseURL: 'http://localhost:8000/api/v1',
});

export const getStats = () => api.get('/stats');
export const getLogs = () => api.get('/logs');
export const getEmissionHistory = () => api.get('/tracking/history');
export const getSuggestions = () => api.get('/suggestions');

export const trackEmission = (data) => api.post('/tracking', data);

export const sendMessage = (message) => api.post('/chatbot/message', { message });
